  <script>
    function createConfetti() {
      const colors = ['#FF6B9D', '#4ECDC4', '#FFE66D', '#A8E6CF', '#9370DB', '#20B2AA'];
      for (let i = 0; i < 25; i++) {
        setTimeout(() => {
          const conf = document.createElement('div');
          conf.style.position = 'fixed';
          conf.style.width = (Math.random() * 8 + 6) + 'px';
          conf.style.height = conf.style.width;
          conf.style.left = Math.random() * 100 + '%';
          conf.style.backgroundColor = colors[Math.floor(Math.random() * colors.length)];
          conf.style.borderRadius = Math.random() > 0.5 ? '50%' : '0';
          conf.style.top = '-20px';
          conf.style.opacity = '0.7';
          conf.style.pointerEvents = 'none';
          conf.style.zIndex = '999';
          conf.style.animation = `confettiFall ${Math.random() * 3 + 4}s linear forwards`;
          document.body.appendChild(conf);
          setTimeout(() => conf.remove(), 8000);
        }, i * 80);
      }
    }
    const style = document.createElement('style');
    style.textContent = `@keyframes confettiFall { to { transform: translateY(100vh) rotate(360deg); opacity: 0; } }`;
    document.head.appendChild(style);
    window.addEventListener('load', () => {
      createConfetti();
      setInterval(createConfetti, 7000);
    });
    document.getElementById('doneBtn')?.addEventListener('click', function(e) {
      e.preventDefault();
      const rect = this.getBoundingClientRect();
      const x = (rect.left + rect.width / 2) / window.innerWidth;
      const y = (rect.top + rect.height / 2) / window.innerHeight;
      confetti({ particleCount: 150, spread: 100, origin: { x, y }, colors: ['#20B2AA', '#9370DB', '#FF6B9D', '#FFE66D', '#4ECDC4'] });
      setTimeout(() => window.location.href = '../index.html', 300);
    });
  </script>
</body>
